import { useMemo } from 'react';
import { Box, Flex, Link, useBoolean } from '@chakra-ui/react';
import { isValid, parseISO, subYears } from 'date-fns';
import { Trans, useTranslation } from 'react-i18next';
import * as yup from 'yup';
import { IErrorResponse } from '@domain/error';
import { useAuthStore } from '@state/authStore';
import { UpdateUserDetailsParams } from '@state/org/users';
import { Button } from '@ui/components/Button';
import { serializeDate } from '@ui/components/filters/serde';
import { Form } from '@ui/components/formControls/Form';
import { FormGroup } from '@ui/components/formControls/FormGroup';
import { FormInputControl, InputControl } from '@ui/components/formControls/InputControl';
import { FormMaskedInputControl } from '@ui/components/formControls/MaskedInputControl';
import { FormSignaturePadControl } from '@ui/components/formControls/SignaturePadControl';
import { FormAddressControl } from '@ui/components/formControls/compositions/AddressControl';
import { Meta, Paragraph } from '@ui/components/typography';

export type AcceptParams = {
  account: { signature: string };
  user: UpdateUserDetailsParams;
};

type Props = {
  accountSlug?: string;
  onSubmit: (values: AcceptParams) => void;
  serverError?: IErrorResponse;
  useBlankSignature?: boolean;
};

const ssnWithDashes = (ssn: string) => [ssn.slice(0, 3), ssn.slice(3, 5), ssn.slice(5)].join('-');
export const formId = 'org-application/financial-authority/acceptance';

export const AcceptanceForm = ({
  accountSlug,
  onSubmit,
  serverError,
  useBlankSignature = false,
}: Props) => {
  const [changingSSN, { off: stopChangingSSN, on: startChangingSSN }] = useBoolean(false);
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'financialAuthority' });
  const { t: tSignature } = useTranslation('organizationApplication', { keyPrefix: 'signature' });
  const { t: tCommon } = useTranslation('common');
  const { user } = useAuthStore();

  const schema = yup.object().shape({
    ...((!user?.ssn || changingSSN) && {
      ssn: yup.string().length(9).required(t('confirmInformation.errors.ssn')),
    }),
    dob: yup
      .date()
      .max(subYears(new Date(), 18), t('confirmInformation.errors.dobMax'))
      .required(t('confirmInformation.errors.dob')),
    signature: yup.string().required(),
  });

  const initialValues = useMemo(() => {
    const dob = user?.dateOfBirth ? parseISO(user.dateOfBirth) : undefined;
    return {
      city: user?.city ?? '',
      country: 'US',
      dob: isValid(dob) ? dob : undefined, // parseISO returns Invalid Date on failure
      firstName: user?.firstName,
      lastName: user?.lastName,
      line1: user?.line1 ?? '',
      line2: user?.line2 ?? '',
      postalCode: user?.postalCode ?? '',
      region: user?.region ?? '',
      signature: useBlankSignature ? '' : user?.signature.url ?? '',
      ...(!user?.ssn && { ssn: '' }),
    };
  }, [
    useBlankSignature,
    user?.dateOfBirth,
    user?.city,
    user?.firstName,
    user?.lastName,
    user?.line1,
    user?.line2,
    user?.postalCode,
    user?.region,
    user?.signature.url,
    user?.ssn,
  ]);

  const handleSubmit = ({
    city,
    dob,
    line1,
    postalCode,
    region,
    signature,
    ssn,
  }: typeof initialValues) => {
    onSubmit({
      account: { signature },
      user: {
        city,
        dateOfBirth: serializeDate(dob),
        line1,
        postalCode,
        region,
        signature,
        ...(ssn && { ssn: ssnWithDashes(ssn) }),
      },
    });
  };

  return (
    <Form
      display="flex"
      flexDirection="column"
      gap={6}
      id={formId}
      initialValues={initialValues}
      onSubmit={handleSubmit}
      schema={schema}
      serverError={serverError}
    >
      <FormGroup mb={0} title={t('confirmInformation.title')}>
        <Paragraph>
          <Trans
            components={[
              <Link
                href="https://www.fincen.gov/resources/statutes-regulations/usa-patriot-act"
                isExternal
                key="patriot-act-link"
              />,
            ]}
            i18nKey="confirmInformation.patriotAct"
            t={t}
          />
        </Paragraph>
      </FormGroup>
      <FormGroup mb={0} title={t('confirmInformation.subheadings.legalInformation')}>
        <Flex gap={2}>
          <FormInputControl
            isDisabled
            label={t('confirmInformation.inputs.firstName')}
            name="firstName"
          />
          <FormInputControl
            isDisabled
            label={t('confirmInformation.inputs.lastName')}
            name="lastName"
          />
        </Flex>
        <Flex gap={2}>
          {changingSSN || !user?.ssn ? (
            <Box>
              <FormMaskedInputControl
                formControlProps={{ marginBottom: 0 }}
                isRequired
                label={t('confirmInformation.inputs.ssn')}
                name="ssn"
                type="ssn"
              />
              {user?.ssn && (
                <Button color="blue.500" onClick={stopChangingSSN} variant="unstyled">
                  {t('confirmInformation.useCurrentSSN')}
                </Button>
              )}
            </Box>
          ) : (
            <Box>
              <InputControl
                formControlProps={{ marginBottom: 0 }}
                isDisabled
                label={t('confirmInformation.inputs.ssn')}
                name="existing-ssn"
                value={user.ssn}
              />
              <Button color="blue.500" onClick={startChangingSSN} variant="unstyled">
                {t('confirmInformation.changeSSN')}
              </Button>
            </Box>
          )}
          <FormMaskedInputControl
            isRequired
            label={t('confirmInformation.inputs.dob')}
            name="dob"
            type="fullDate"
          />
        </Flex>
      </FormGroup>
      <FormGroup mb={0} title={t('confirmInformation.subheadings.address')}>
        <FormAddressControl
          accountSlug={accountSlug}
          allowedCountries={['US']}
          isRequired
          label={tCommon('street')}
        />
      </FormGroup>
      <FormGroup mb={0} title={tSignature('heading')}>
        <Meta>
          <Trans
            components={[<Box as="span" color="red.500" key="description-text" />]}
            i18nKey="description"
            t={tSignature}
          />
