import { useMemo } from 'react';
import { useWatch } from 'react-hook-form';
import { CountryValues } from 'src/domain/constants/countryOptions';
import { PublicActionPage } from '@domain/publicActionPage';
import { FormAddressInputs } from '../AddressInputs';
import { FormAddressInputsProps } from '../AddressInputs/FormAddressInputs';
import { SmartyAddressInputProps } from '../SmartyAddressInput/SmartyAddressInput';
import { getFieldNames } from './getFieldNames';

export type FormAddressControlProps = Pick<
  SmartyAddressInputProps,
  'label' | 'isRequired' | 'disabledAutoSuggest'
> &
  Pick<FormAddressInputsProps, 'showCountrySelect' | 'showLine2'> & {
    accountSlug?: string;
    actionPage?: PublicActionPage;
    allowedCountries?: CountryValues[];
    fieldPrefix?: string | undefined;
    fieldPrefixDelimiter?: string;
  };

export const FormAddressControl = (props: FormAddressControlProps) => {
  const { allowedCountries, fieldPrefix, fieldPrefixDelimiter } = props;

  const { fieldCity, fieldCountry, fieldLine1, fieldLine2, fieldPostalCode, fieldRegion } =
    getFieldNames(fieldPrefix, fieldPrefixDelimiter);

  const line1 = useWatch({ name: fieldLine1 });
  const line2 = useWatch({ name: fieldLine2 });
  const city = useWatch({ name: fieldCity });
  const region = useWatch({ name: fieldRegion });
  const postalCode = useWatch({ name: fieldPostalCode });
  const country = useWatch({ name: fieldCountry });

  const hasInput = useMemo(() => {
    const all = [line1, line2, city, region, postalCode];

    if (!allowedCountries || allowedCountries.length > 1) {
      all.push(country);
    }

    return !!all.reduce((acc, field) => acc + (field ? field.length : 0), 0);
  }, [line1, line2, city, region, postalCode, allowedCountries, country]);

  return (
    <FormAddressInputs
      {...props}
      fieldPrefix={fieldPrefix}
      fieldPrefixDelimiter={fieldPrefixDelimiter}
      showAllInputs={hasInput}
    />
  );
};
